package org.example.management.service;

import lombok.RequiredArgsConstructor;
import org.example.common.exception.BusinessException;
import org.example.management.dto.RequestGroupDto;
import org.example.management.entity.CustomerSegment;
import org.example.management.entity.RequestGroup;
import org.example.management.repository.CustomerSegmentRepository;
import org.example.management.repository.RequestGroupRepository;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
public class RequestGroupService {

    private final RequestGroupRepository repository;
    private final CustomerSegmentRepository customerSegmentRepository;

    private RequestGroupDto mapToDto(RequestGroup entity) {
        return RequestGroupDto.builder()
                .id(entity.getId())
                .customerSegmentId(entity.getCustomerSegment() != null ? entity.getCustomerSegment().getId() : null)
                .code(entity.getCode())
                .prefixCode(entity.getPrefixCode())
                .name(entity.getName())
                .description(entity.getDescription())
                .isActive(entity.getIsActive())
                .build();
    }

    public List<RequestGroupDto> getAll() {
        return repository.findAll().stream()
                .map(this::mapToDto)
                .collect(Collectors.toList());
    }

    public RequestGroupDto getById(Long id) {
        RequestGroup entity = repository.findById(id)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Request group not found"));
        return mapToDto(entity);
    }

    @Transactional
    public RequestGroupDto create(RequestGroupDto dto) {
        if (repository.existsByCode(dto.getCode())) {
            throw new BusinessException(HttpStatus.CONFLICT, "Code already exists");
        }
        if (repository.existsByPrefixCode(dto.getPrefixCode())) {
            throw new BusinessException(HttpStatus.CONFLICT, "Prefix code already exists");
        }

        CustomerSegment customerSegment = customerSegmentRepository.findById(dto.getCustomerSegmentId())
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Customer segment not found"));

        RequestGroup entity = RequestGroup.builder()
                .customerSegment(customerSegment)
                .code(dto.getCode())
                .prefixCode(dto.getPrefixCode())
                .name(dto.getName())
                .description(dto.getDescription())
                .isActive(dto.getIsActive() != null ? dto.getIsActive() : true)
                .build();

        return mapToDto(repository.save(entity));
    }

    @Transactional
    public RequestGroupDto update(Long id, RequestGroupDto dto) {
        RequestGroup entity = repository.findById(id)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Request group not found"));

        if (!entity.getCode().equals(dto.getCode()) && repository.existsByCode(dto.getCode())) {
            throw new BusinessException(HttpStatus.CONFLICT, "Code already exists");
        }
        if (!entity.getPrefixCode().equals(dto.getPrefixCode()) && repository.existsByPrefixCode(dto.getPrefixCode())) {
            throw new BusinessException(HttpStatus.CONFLICT, "Prefix code already exists");
        }

        CustomerSegment customerSegment = customerSegmentRepository.findById(dto.getCustomerSegmentId())
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Customer segment not found"));

        entity.setCustomerSegment(customerSegment);
        entity.setCode(dto.getCode());
        entity.setPrefixCode(dto.getPrefixCode());
        entity.setName(dto.getName());
        entity.setDescription(dto.getDescription());
        if (dto.getIsActive() != null) {
            entity.setIsActive(dto.getIsActive());
        }

        return mapToDto(repository.save(entity));
    }
}

package org.example.management.service;

import lombok.RequiredArgsConstructor;
import org.example.common.exception.BusinessException;
import org.example.management.dto.RequestGroupDto;
import org.example.management.dto.RequestGroupWithServicesDto;
import org.example.management.dto.ServiceTypeDto;
import org.example.management.entity.CustomerSegment;
import org.example.management.entity.RequestGroup;
import org.example.management.repository.CustomerSegmentRepository;
import org.example.management.repository.RequestGroupRepository;
import org.example.management.repository.ServiceTypeRepository;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
public class RequestGroupService {

    private final RequestGroupRepository repository;
    private final CustomerSegmentRepository customerSegmentRepository;
    private final ServiceTypeRepository serviceTypeRepository;

    private RequestGroupDto mapToDto(RequestGroup entity) {
        return RequestGroupDto.builder()
                .id(entity.getId())
                .customerSegmentId(entity.getCustomerSegment() != null ? entity.getCustomerSegment().getId() : null)
                .code(entity.getCode())
                .prefixCode(entity.getPrefixCode())
                .name(entity.getName())
                .description(entity.getDescription())
                .isActive(entity.getIsActive())
                .build();
    }

    public List<RequestGroupDto> getAll() {
        return repository.findAll().stream()
                .map(this::mapToDto)
                .collect(Collectors.toList());
    }

    public RequestGroupDto getById(Long id) {
        RequestGroup entity = repository.findById(id)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Request group not found"));
        return mapToDto(entity);
    }

    private RequestGroupWithServicesDto mapToWithServicesDto(RequestGroup entity, List<ServiceTypeDto> services) {
        return RequestGroupWithServicesDto.builder()
                .id(entity.getId())
                .customerSegmentId(entity.getCustomerSegment() != null ? entity.getCustomerSegment().getId() : null)
                .code(entity.getCode())
                .prefixCode(entity.getPrefixCode())
                .name(entity.getName())
                .description(entity.getDescription())
                .isActive(entity.getIsActive())
                .services(services)
                .build();
    }

    private ServiceTypeDto mapServiceToDto(org.example.management.entity.ServiceType entity) {
        return ServiceTypeDto.builder()
                .id(entity.getId())
                .requestGroupId(entity.getRequestGroup() != null ? entity.getRequestGroup().getId() : null)
                .code(entity.getCode())
                .name(entity.getName())
                .averageServiceMinutes(entity.getAverageServiceMinutes())
                .priorityWeight(entity.getPriorityWeight())
                .slaMinutes(entity.getSlaMinutes())
                .isActive(entity.getIsActive())
                .build();
    }

    public List<RequestGroupWithServicesDto> getAllWithServices() {
        return repository.findAll().stream()
                .map(entity -> {
                    List<ServiceTypeDto> services = serviceTypeRepository.findByRequestGroupId(entity.getId())
                            .stream().map(this::mapServiceToDto).collect(Collectors.toList());
                    return mapToWithServicesDto(entity, services);
                })
                .collect(Collectors.toList());
    }

    public RequestGroupWithServicesDto getByIdWithServices(Long id) {
        RequestGroup entity = repository.findById(id)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Request group not found"));
        List<ServiceTypeDto> services = serviceTypeRepository.findByRequestGroupId(entity.getId())
                .stream().map(this::mapServiceToDto).collect(Collectors.toList());
        return mapToWithServicesDto(entity, services);
    }

    @Transactional
    public RequestGroupDto create(RequestGroupDto dto) {
        if (repository.existsByCode(dto.getCode())) {
            throw new BusinessException(HttpStatus.CONFLICT, "Code already exists");
        }
        if (repository.existsByPrefixCode(dto.getPrefixCode())) {
            throw new BusinessException(HttpStatus.CONFLICT, "Prefix code already exists");
        }

        CustomerSegment customerSegment = customerSegmentRepository.findById(dto.getCustomerSegmentId())
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Customer segment not found"));

        RequestGroup entity = RequestGroup.builder()
                .customerSegment(customerSegment)
                .code(dto.getCode())
                .prefixCode(dto.getPrefixCode())
                .name(dto.getName())
                .description(dto.getDescription())
                .isActive(dto.getIsActive() != null ? dto.getIsActive() : true)
                .build();

        return mapToDto(repository.save(entity));
    }

    @Transactional
    public RequestGroupDto update(Long id, RequestGroupDto dto) {
        RequestGroup entity = repository.findById(id)
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Request group not found"));

        if (!entity.getCode().equals(dto.getCode()) && repository.existsByCode(dto.getCode())) {
            throw new BusinessException(HttpStatus.CONFLICT, "Code already exists");
        }
        if (!entity.getPrefixCode().equals(dto.getPrefixCode()) && repository.existsByPrefixCode(dto.getPrefixCode())) {
            throw new BusinessException(HttpStatus.CONFLICT, "Prefix code already exists");
        }

        CustomerSegment customerSegment = customerSegmentRepository.findById(dto.getCustomerSegmentId())
                .orElseThrow(() -> new BusinessException(HttpStatus.NOT_FOUND, "Customer segment not found"));

        entity.setCustomerSegment(customerSegment);
        entity.setCode(dto.getCode());
        entity.setPrefixCode(dto.getPrefixCode());
        entity.setName(dto.getName());
        entity.setDescription(dto.getDescription());
        if (dto.getIsActive() != null) {
            entity.setIsActive(dto.getIsActive());
        }

        return mapToDto(repository.save(entity));
    }
}

package org.example.ticket.controller;

import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.example.common.dto.ApiResponse;
import org.example.ticket.dto.TicketCreateRequest;
import org.example.ticket.dto.TicketDto;
import org.example.ticket.entity.enums.TicketStatus;
import org.example.ticket.service.TicketService;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;
import org.example.ticket.dto.QueueItemDto;
import org.example.ticket.context.UserContextHolder;

import java.time.LocalDate;
import java.util.List;

@RestController
@RequestMapping("/api/v1/ticket/tickets")
@RequiredArgsConstructor
public class TicketController {

    private final TicketService service;

    @GetMapping
    public ApiResponse<List<TicketDto>> getTickets(
            @RequestParam("branchId") Long branchId,
            @RequestParam(value = "status", required = false) TicketStatus status,
            @RequestParam(value = "date", required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate date) {

        LocalDate queryDate = date != null ? date : LocalDate.now();
        if (status != null) {
            return ApiResponse.success(service.getTicketsByStatus(branchId, queryDate, status));
        }
    public ApiResponse<TicketDto> getById(@PathVariable("id") Long id) {
    }

    @GetMapping("/{id}")
    public ApiResponse<TicketDto> getById(@PathVariable Long id) {
        return ApiResponse.success(service.getById(id));
    }

    @PostMapping("/create")
    @ResponseStatus(HttpStatus.CREATED)
    public ApiResponse<TicketDto> createTicket(
            @RequestHeader(value = "X-Auth-User-Id", required = false) Long userId,
            @Valid @RequestBody TicketCreateRequest request) {

        // userId có thể null nếu request đến trực tiếp từ màn hình Kiosk (không yêu cầu đăng nhập)
        return ApiResponse.success(service.create(request, userId), "Ticket generated successfully");
    }

    @PutMapping("/{id}/status")
            @PathVariable("id") Long id,
            @RequestBody TicketStatus status) {
        Long userId = UserContextHolder.getUserId();

        return ApiResponse.success(service.updateStatus(id, status, userId), "Ticket status updated");
    }

    @PostMapping("/{id}/rejoin")
    public ApiResponse<TicketDto> rejoinTicket(
            @RequestHeader("X-Auth-User-Id") Long userId,
            @PathVariable Long id) {
            @PathVariable("id") Long id) {
    }

    @PostMapping("/{id}/transfer")
    public ApiResponse<TicketDto> transferTicket(
            @RequestHeader("X-Auth-User-Id") Long userId,
            @PathVariable Long id,
            @RequestParam Long newRequestGroupId,
            @PathVariable("id") Long id,
            @RequestParam("newRequestGroupId") Long newRequestGroupId,
            @RequestParam(value = "newServiceTypeId", required = false) Long newServiceTypeId) {
    }

    @GetMapping("/next-in-queue")
    public ApiResponse<List<QueueItemDto>> getNextTicketsForCounter() {
        Long userId = UserContextHolder.getUserId();
        return ApiResponse.success(service.getNextTicketsForCounter(userId));
    }

    @GetMapping("/top-in-queue")
    public ApiResponse<QueueItemDto> getTopTicketForCounter() {
        Long userId = UserContextHolder.getUserId();
        return ApiResponse.success(service.getTopTicketForCounter(userId));
    }

    @PostMapping("/call-next")
    public ApiResponse<TicketDto> callNextTicket() {
        Long userId = UserContextHolder.getUserId();
        return ApiResponse.success(service.callNextTicket(userId), "Successfully called the top priority ticket");
    }

    @GetMapping("/current")
    public ApiResponse<TicketDto> getCurrentTicket() {
        Long userId = UserContextHolder.getUserId();
        return ApiResponse.success(service.getCurrentTicketForCounter(userId));
    }

    @GetMapping("/topics")
    public ApiResponse<List<String>> getCounterSubscriptionTopics() {
        Long userId = UserContextHolder.getUserId();
        return ApiResponse.success(service.getSubscriptionTopics(userId));
    }
}

package org.example.ticket.controller;

import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.example.common.dto.ApiResponse;
import org.example.ticket.dto.TicketCreateRequest;
import org.example.ticket.dto.TicketDto;
import org.example.ticket.entity.enums.TicketStatus;
import org.example.ticket.service.TicketService;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;
import org.example.ticket.dto.QueueItemDto;
import org.example.ticket.context.UserContextHolder;

import java.time.LocalDate;
import java.util.List;

@RestController
@RequestMapping("/api/v1/ticket/tickets")
@RequiredArgsConstructor
public class TicketController {

    private final TicketService service;

    @GetMapping
    public ApiResponse<List<TicketDto>> getTickets(
            @RequestParam("branchId") Long branchId,
            @RequestParam(value = "status", required = false) TicketStatus status,
            @RequestParam(value = "date", required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate date) {

        LocalDate queryDate = date != null ? date : LocalDate.now();
        if (status != null) {
            return ApiResponse.success(service.getTicketsByStatus(branchId, queryDate, status));
        }
        return ApiResponse.success(service.getTicketsByBranchAndDate(branchId, queryDate));
    }

    @GetMapping("/{id}")
    public ApiResponse<TicketDto> getById(@PathVariable("id") Long id) {
        return ApiResponse.success(service.getById(id));
    }

    @PostMapping("/create")
    @ResponseStatus(HttpStatus.CREATED)
    public ApiResponse<TicketDto> createTicket(
            @RequestHeader(value = "X-Auth-User-Id", required = false) Long userId,
            @Valid @RequestBody TicketCreateRequest request) {
        return ApiResponse.success(service.create(request, userId), "Ticket generated successfully");
    }

    @PutMapping("/{id}/status")
    public ApiResponse<TicketDto> updateStatus(
            @PathVariable("id") Long id,
            @RequestBody TicketStatus status) {
        Long userId = UserContextHolder.getUserId();
        return ApiResponse.success(service.updateStatus(id, status, userId), "Ticket status updated");
    }

    @PostMapping("/{id}/rejoin")
    public ApiResponse<TicketDto> rejoinTicket(
